record.field:
for shipment in records:
    if shipment.state != 'delivered':
        raise UserError('Solo se pueden crear consolidaciones desde embarques entregados.')

    existing = env['lumber.billing.consolidation'].search([
        ('shipment_id', '=', shipment.id),
        ('state', '!=', 'cancelled')
    ], limit=1)

    if existing:
        action = {
            'type': 'ir.actions.act_window',
            'name': 'Consolidación de Facturación',
            'res_model': 'lumber.billing.consolidation',
            'res_id': existing.id,
            'view_mode': 'form',
            'target': 'current',
        }
    else:
        consolidation = env['lumber.billing.consolidation'].create({
            'shipment_id': shipment.id,
            'state': 'draft',
        })
        action = {
            'type': 'ir.actions.act_window',
            'name': 'Consolidación de Facturación',
            'res_model': 'lumber.billing.consolidation',
            'res_id': consolidation.id,
            'view_mode': 'form',
            'target': 'current',
        }
